{
  "name": "magicbell-floating-inbox-demo",
  "private": true,
  "version": "0.1.0",
  "type": "module",
  "scripts": {
    "dev": "vite --port 3000",
    "server": "node server.js",
    "start": "concurrently \"npm run server\" \"npm run dev\""
  },
  "dependencies": {
    "@magicbell/react": "^13.5.0",
    "express": "^4.19.2",
    "jsonwebtoken": "^9.0.2",
    "react": "^18.2.0",
    "react-dom": "^18.2.0"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.2.1",
    "concurrently": "^8.2.2",
    "vite": "^5.4.1"
  }
}

import express from "express";
import jwt from "jsonwebtoken";

const app = express();
const port = 3001;

const {
  MAGICBELL_EMAIL,
  MAGICBELL_PROJECT_TOKEN,
  MAGICBELL_API_KEY,
  MAGICBELL_SECRET_KEY,
  ZEALT_RUN_ID
} = process.env;

const requireEnv = (key, value) => {
  if (!value) {
    throw new Error(`Missing required environment variable: ${key}`);
  }
};

requireEnv("MAGICBELL_EMAIL", MAGICBELL_EMAIL);
requireEnv("MAGICBELL_PROJECT_TOKEN", MAGICBELL_PROJECT_TOKEN);
requireEnv("MAGICBELL_API_KEY", MAGICBELL_API_KEY);
requireEnv("MAGICBELL_SECRET_KEY", MAGICBELL_SECRET_KEY);
requireEnv("ZEALT_RUN_ID", ZEALT_RUN_ID);

const [localPart, domainPart] = MAGICBELL_EMAIL.split("@");
const userEmail = `${localPart}+fi-${ZEALT_RUN_ID}@${domainPart}`;
const userExternalId = `user-fi-${ZEALT_RUN_ID}`;
const broadcastTitle = `Floating Inbox - ${ZEALT_RUN_ID}`;

const magicbellBaseUrl = "https://api.magicbell.com/v2";
const magicbellHeaders = {
  "Content-Type": "application/json",
  "X-MAGICBELL-API-KEY": MAGICBELL_API_KEY,
  "X-MAGICBELL-API-SECRET": MAGICBELL_SECRET_KEY
};

const upsertUser = async () => {
  const body = JSON.stringify({
    external_id: userExternalId,
    email: userEmail
  });

  const createResponse = await fetch(`${magicbellBaseUrl}/users`, {
    method: "POST",
    headers: magicbellHeaders,
    body
  });

  if (createResponse.ok) {
    return;
  }

  if (createResponse.status === 422) {
    const updateResponse = await fetch(
      `${magicbellBaseUrl}/users/${encodeURIComponent(userExternalId)}`,
      {
        method: "PUT",
        headers: magicbellHeaders,
        body
      }
    );

    if (!updateResponse.ok) {
      const errorText = await updateResponse.text();
      throw new Error(`Failed to update MagicBell user: ${updateResponse.status} ${errorText}`);
    }

    return;
  }

  const errorText = await createResponse.text();
  throw new Error(`Failed to create MagicBell user: ${createResponse.status} ${errorText}`);
};

const createSeedBroadcast = async () => {
  const body = JSON.stringify({
    title: broadcastTitle,
    content: `Welcome to the Floating Inbox demo for ${ZEALT_RUN_ID}.`,
    recipients: {
      external_id: [userExternalId]
    }
  });

  const response = await fetch(`${magicbellBaseUrl}/broadcasts`, {
    method: "POST",
    headers: magicbellHeaders,
    body
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Failed to create MagicBell broadcast: ${response.status} ${errorText}`);
  }
};

const ensureMagicBellSetup = async () => {
  await upsertUser();
  await createSeedBroadcast();
};

app.get("/token", (req, res) => {
  const token = jwt.sign(
    {
      user_email: userEmail,
      user_external_id: userExternalId,
      api_key: MAGICBELL_PROJECT_TOKEN
    },
    MAGICBELL_SECRET_KEY,
    {
      algorithm: "HS256",
      expiresIn: "365d"
    }
  );

  res.json({ token });
});

app.get("/", (req, res) => {
  res.json({ status: "ok" });
});

const start = async () => {
  await ensureMagicBellSetup();

  app.listen(port, () => {
    console.log(`MagicBell demo backend running on port ${port}`);
  });
};

start().catch((error) => {
  console.error("Failed to start server", error);
  process.exit(1);
});

import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  server: {
    port: 3000,
    proxy: {
      "/token": "http://localhost:3001"
    }
  }
});

import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App.jsx";
import "./styles.css";

ReactDOM.createRoot(document.getElementById("root")).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { useEffect, useState } from "react";
import MagicBellProvider from "@magicbell/react/context-provider";
import FloatingInbox from "@magicbell/react/floating-inbox";
import "@magicbell/react/styles/floating-inbox.css";

const projectToken = import.meta.env.VITE_MAGICBELL_PROJECT_TOKEN;
const runId = import.meta.env.VITE_ZEALT_RUN_ID;

const App = () => {
  const [userToken, setUserToken] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    const loadToken = async () => {
      try {
        const response = await fetch("/token");
        if (!response.ok) {
          throw new Error(`Token request failed: ${response.status}`);
        }
        const data = await response.json();
        setUserToken(data.token);
      } catch (err) {
        setError(err.message || "Failed to load token");
      }
    };

    loadToken();
  }, []);

  return (
    <div className="app">
      <header className="app-header">
        <div>
          <p className="eyebrow">MagicBell Demo</p>
          <h1>Floating Inbox</h1>
          <p className="muted">Run ID: {runId || "(missing VITE_ZEALT_RUN_ID)"}</p>
        </div>
        <div className="bell-container">
          {error ? (
            <span className="error">{error}</span>
          ) : userToken ? (
            <MagicBellProvider apiKey={projectToken} userToken={userToken}>
              <FloatingInbox placement="bottom-end" />
            </MagicBellProvider>
          ) : (
            <span className="loading">Loading inbox…</span>
          )}
        </div>
      </header>
      <main className="content">
        <p>
          The floating inbox is connected to MagicBell using a signed user JWT
          from the Express backend. Click the bell icon to open the inbox and see
          the seeded notification titled <strong>Floating Inbox - {runId}</strong>.
        </p>
      </main>
    </div>
  );
};

export default App;

:root {
  font-family: "Inter", system-ui, sans-serif;
  color: #1f2937;
  background: #f8fafc;
}

* {
  box-sizing: border-box;
}

